    for (int i = 0; i < n; ++i) {
        std::string r;
        std::cin >> r;
        rels.push_back(r);
    }
    // Sort descending (strongest first): swap when left rank < right rank
    for (int i = 0; i < n - 1; ++i) {
        for (int j = i + 1; j < n; ++j) {
            if (rankOf(rels[static_cast<std::size_t>(i)]) < rankOf(rels[static_cast<std::size_t>(j)])) {
                std::string tmp = rels[static_cast<std::size_t>(i)];
                rels[static_cast<std::size_t>(i)] = rels[static_cast<std::size_t>(j)];
                rels[static_cast<std::size_t>(j)] = tmp;
            }
        }
    }
    for (const auto& r : rels) {
        std::cout << r << "\n";
    }
    return 0;
}
